mapper.select:
select id, code, name, min_length as minLength, max_length as maxLength, expire_days as expireDays, retry_limit as retryLimit, lock_minutes as lockMinutes, status, create_time, update_time from password_policy
and `name` like concat('%', #{request.name}, '%')
and `code` = #{request.code}
and `status` = #{request.status}
order by create_time desc
